// ── FAQ ──
function FAQ() {
  const [open, setOpen] = useState(null);
  const items = [
    { q: "What is RevPhlo?", a: "RevPhlo is a sales intelligence platform built for high-ticket sales teams. It provides AI-powered post-call notes, revenue attribution from ad click to cash collected, live sales leaderboards ranked by real revenue, and automated payment matching — replacing manual EOD reports, spreadsheet dashboards, and fragmented reporting with a single real-time dashboard." },
    { q: "What CRMs and tools does RevPhlo integrate with?", a: "RevPhlo integrates with GoHighLevel, HubSpot, Stripe, ThriveCart, Whop, Fathom, Zoom, and Slack. It connects to your existing CRM and payment processor in 48 hours with no migration required." },
    { q: "Who is RevPhlo built for?", a: "High-ticket setter-closer sales teams with 3 or more closers, selling offers at $3,000+, and doing $100K+ per month in revenue. Typical customers include coaching companies, info product businesses, high-ticket service providers, and agency-model businesses." },
    { q: "How long does setup take?", a: "Most teams are fully live within 48 hours. Connect your integrations, map your sources and calendars, and your dashboard starts populating immediately. No data migration required." },
    { q: "How do the AI post-call notes work?", a: "RevPhlo pulls from your call recordings via Fathom or Zoom and uses AI to auto-generate post-call summaries — outcome, objections raised, prospect sentiment, commitments, and follow-up actions. Closers just review and confirm. No manual EOD reports needed." },
    { q: "Does RevPhlo replace GoHighLevel or HubSpot?", a: "No. RevPhlo is not a CRM. It works alongside your existing CRM — whether GoHighLevel, HubSpot, or another supported platform. You keep your CRM for lead management, pipeline tracking, and appointment booking. RevPhlo adds the post-booking intelligence layer: what happened on the call, who collected the most cash, which ad source produced real revenue, and which closers need coaching." },
    { q: "How is RevPhlo different from spreadsheets?", a: "Spreadsheets require manual data entry, are always stale, and depend on human accuracy. RevPhlo pulls data automatically from your CRM, payment processors, and call recorders with zero manual entry. Real-time data, always accurate, no reconciliation needed." },
    { q: "How is RevPhlo different from Databox or other dashboard tools?", a: "Databox is a general-purpose dashboard builder you configure yourself. RevPhlo is pre-configured for high-ticket sales teams — the dashboards are already built with the specific views and metrics that matter for setter-closer operations. No setup, no configuration, no maintenance." },
    { q: "What payment processors does RevPhlo support?", a: "RevPhlo integrates with Stripe, ThriveCart, and Whop. It automatically matches payments from any supported processor to the closer who earned the revenue, the call it came from, and the traffic source that generated the lead." },
    { q: "Can my sales reps see their own data?", a: "Yes — every rep gets their own portal with personal KPIs, a daily task queue, call recordings, and shareable leaderboard wins." },
    { q: "What is revenue attribution in RevPhlo?", a: "RevPhlo traces every dollar of cash collected back through the full path: the original ad source, the funnel, the setter who booked the appointment, the closer who ran the call, and the payment that confirmed the deal — regardless of which payment processor was used." },
    { q: "How much does RevPhlo cost?", a: "Pricing is based on team size. Apply for a demo to see the platform with your own data and get a custom quote." },
  ];
  return (
    <section style={{ padding: "120px 32px", textAlign: "center" }} id="faq">
      <div style={{ maxWidth: 1140, margin: "0 auto" }}>
        <Reveal>
          <div style={{ fontSize: 13, textTransform: "uppercase", letterSpacing: 2.5, color: T.blue, fontWeight: 600, marginBottom: 16 }}>Questions</div>
          <h2 style={{ fontFamily: "'DM Serif Display',Georgia,serif", fontSize: "clamp(32px,4vw,50px)", lineHeight: 1.12, letterSpacing: -1 }}>Everything you need to know</h2>
        </Reveal>
        <Reveal delay={0.1}>
          <div style={{ maxWidth: 700, margin: "56px auto 0", textAlign: "left" }}>
            {items.map((it, i) => (
              <div key={i} style={{ borderBottom: `1px solid ${T.border}` }}>
                <div
                  onClick={() => setOpen(open === i ? null : i)}
                  style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "22px 0", cursor: "pointer", fontSize: 16, fontWeight: 600, color: T.text, gap: 16, transition: "color 0.2s" }}
                  onMouseOver={(e) => (e.currentTarget.style.color = T.blue)}
                  onMouseOut={(e) => (e.currentTarget.style.color = T.text)}
                >
                  {it.q}
                  <span style={{ fontSize: 20, color: T.text3, transition: "transform 0.3s", transform: open === i ? "rotate(45deg)" : "rotate(0)", flexShrink: 0 }}>+</span>
                </div>
                <div style={{ maxHeight: open === i ? 300 : 0, overflow: "hidden", transition: "max-height 0.35s ease, padding 0.35s ease", paddingBottom: open === i ? 22 : 0 }}>
                  <p style={{ fontSize: 15, color: T.text2, lineHeight: 1.65 }}>{it.a}</p>
                </div>
              </div>
            ))}
          </div>
        </Reveal>
      </div>
    </section>
  );
}

